#include <bits/stdc++.h>
using namespace std;

vector<vector<int>> adj;
vector<bool> vis;

// Recursive DFS
void dfs(int u) {
    vis[u] = true;
    for (int v : adj[u]) {
        if (!vis[v]) {
            dfs(v);
        }
    }
}

// Iterative DFS (avoids stack overflow for large graphs)
void dfs_iter(int start) {
    stack<int> st;
    st.push(start);
    vis[start] = true;
    while (!st.empty()) {
        int u = st.top(); st.pop();
        for (int v : adj[u]) {
            if (!vis[v]) {
                vis[v] = true;
                st.push(v);
            }
        }
    }
}

int main() {
    int n, m;
    cin >> n >> m;
    adj.assign(n + 1, {});
    vis.assign(n + 1, false);
    for (int i = 0; i < m; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    // Count connected components
    int components = 0;
    for (int i = 1; i <= n; i++) {
        if (!vis[i]) {
            dfs(i);
            components++;
        }
    }
    cout << components << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m, src;
    cin >> n >> m >> src;

    vector<vector<int>> adj(n + 1);
    for (int i = 0; i < m; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    vector<int> dist(n + 1, -1);
    queue<int> q;
    dist[src] = 0;
    q.push(src);

    while (!q.empty()) {
        int u = q.front(); q.pop();
        for (int v : adj[u]) {
            if (dist[v] == -1) {   // not visited
                dist[v] = dist[u] + 1;
                q.push(v);          // mark BEFORE push, not after pop
            }
        }
    }

    for (int i = 1; i <= n; i++) {
        cout << "dist[" << i << "] = " << dist[i] << "\n";
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int dx[] = {0, 0, 1, -1};
int dy[] = {1, -1, 0, 0};

int main() {
    int R, C;
    cin >> R >> C;
    vector<string> grid(R);
    for (auto& row : grid) cin >> row;

    // Find start 'S' and end 'E'
    int sr, sc, er, ec;
    for (int i = 0; i < R; i++)
        for (int j = 0; j < C; j++) {
            if (grid[i][j] == 'S') { sr = i; sc = j; }
            if (grid[i][j] == 'E') { er = i; ec = j; }
        }

    vector<vector<int>> dist(R, vector<int>(C, -1));
    queue<pair<int,int>> q;
    dist[sr][sc] = 0;
    q.push({sr, sc});

    while (!q.empty()) {
        auto [r, c] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = r + dx[d], nc = c + dy[d];
            if (nr >= 0 && nr < R && nc >= 0 && nc < C &&
                grid[nr][nc] != '#' && dist[nr][nc] == -1) {
                dist[nr][nc] = dist[r][c] + 1;
                q.push({nr, nc});
            }
        }
    }

    cout << dist[er][ec] << "\n"; // -1 if unreachable
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m;
    cin >> n >> m;
    vector<vector<int>> adj(n + 1);
    for (int i = 0; i < m; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    vector<int> color(n + 1, -1);
    bool bipartite = true;

    for (int start = 1; start <= n && bipartite; start++) {
        if (color[start] != -1) continue;
        queue<int> q;
        color[start] = 0;
        q.push(start);
        while (!q.empty() && bipartite) {
            int u = q.front(); q.pop();
            for (int v : adj[u]) {
                if (color[v] == -1) {
                    color[v] = 1 - color[u]; // flip color
                    q.push(v);
                } else if (color[v] == color[u]) {
                    bipartite = false; // same color on both ends!
                }
            }
        }
    }

    cout << (bipartite ? "YES" : "NO") << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

vector<vector<int>> adj;
vector<bool> vis;

bool hasCycle(int u, int parent) {
    vis[u] = true;
    for (int v : adj[u]) {
        if (!vis[v]) {
            if (hasCycle(v, u)) return true;
        } else if (v != parent) {
            return true; // back edge found
        }
    }
    return false;
}

int main() {
    int n, m; cin >> n >> m;
    adj.assign(n + 1, {});
    vis.assign(n + 1, false);
    for (int i = 0; i < m; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    bool found = false;
    for (int i = 1; i <= n; i++)
        if (!vis[i] && hasCycle(i, -1))
            found = true;
    cout << (found ? "YES" : "NO") << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int dx[] = {0, 0, 1, -1};
int dy[] = {1, -1, 0, 0};

int main() {
    int R, C; cin >> R >> C;
    vector<vector<int>> grid(R, vector<int>(C));
    vector<vector<int>> dist(R, vector<int>(C, -1));
    queue<pair<int,int>> q;

    for (int i = 0; i < R; i++)
        for (int j = 0; j < C; j++) {
            cin >> grid[i][j];
            if (grid[i][j] == 1) {
                dist[i][j] = 0;
                q.push({i, j}); // all sources enqueued at start
            }
        }

    while (!q.empty()) {
        auto [r, c] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = r + dx[d], nc = c + dy[d];
            if (nr >= 0 && nr < R && nc >= 0 && nc < C && dist[nr][nc] == -1) {
                dist[nr][nc] = dist[r][c] + 1;
                q.push({nr, nc});
            }
        }
    }
    // dist[i][j] now holds distance to nearest 1
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) cout << dist[i][j] << " ";
        cout << "\n";
    }
    return 0;
}

