#include <bits/stdc++.h>
using namespace std;

int R, C;
vector<string> grid;
int dx[] = {0, 0, 1, -1};
int dy[] = {1, -1, 0, 0};

void dfs(int r, int c) {
    if (r < 0 || r >= R || c < 0 || c >= C || grid[r][c] != '1') return;
    grid[r][c] = '0'; // mark visited
    for (int d = 0; d < 4; d++) dfs(r + dx[d], c + dy[d]);
}

int main() {
    cin >> R >> C;
    grid.resize(R);
    for (auto& row : grid) cin >> row;

    int islands = 0;
    for (int i = 0; i < R; i++)
        for (int j = 0; j < C; j++)
            if (grid[i][j] == '1') {
                dfs(i, j);
                islands++;
            }

    cout << islands << "\n";
    return 0;
}

